'use client';
// ============================================================================
// MATERIALI PAGE
// Educational materials and guided learning with Maieutic method
// Related: T-16 Materials page redesign
// ============================================================================

import { HomeworkHelpView } from '@/components/education/homework-help-view';

export default function MaterialiPage() {
  return (
    <div className="container mx-auto py-6 px-4 max-w-7xl">
      <HomeworkHelpView />
    </div>
  );
}

content.content:
     1→'use client';
     2→
     3→import { useState, useCallback } from 'react';
     4→import { motion, AnimatePresence } from 'framer-motion';
     5→import {
     6→  History,
     7→  Trash2,
     8→  X,
     9→  MessageCircle,
    10→  Send,
    11→  Loader2,
    12→  CheckCircle,
    13→  GraduationCap,
    14→} from 'lucide-react';
    15→import dynamic from 'next/dynamic';
    16→
    17→// Dynamic import to avoid SSR issues with pdfjs (uses DOMMatrix)
    18→const HomeworkHelp = dynamic(
    19→  () => import('./homework-help').then((mod) => mod.HomeworkHelp),
    20→  { ssr: false }
    21→);
    22→import { SubjectConfirmationDialog } from './subject-confirmation-dialog';
    23→import { Button } from '@/components/ui/button';
    24→import { logger } from '@/lib/logger';
    25→import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
    26→import { cn } from '@/lib/utils';
    27→import { useVoiceSessionStore } from '@/lib/stores/app-store';
    28→import { useHomeworkSessions, type SavedHomework } from '@/lib/hooks/use-saved-materials';
    29→import type { Homework, Subject, Maestro } from '@/types';
    30→
    31→interface MaieuticMessage {
    32→  role: 'user' | 'assistant';
    33→  content: string;
    34→  timestamp: Date;
    35→}
    36→
    37→// Maieutic system prompt for homework help
    38→const MAIEUTIC_SYSTEM_PROMPT = `Sei un tutor educativo che usa il metodo maieutico (socratico).
    39→Il tuo obiettivo NON è dare le risposte, ma guidare lo studente a trovare la soluzione da solo.
    40→
    41→Quando analizzi un problema:
    42→1. Identifica i concetti chiave necessari
    43→2. Crea passaggi logici che guidano verso la soluzione
    44→3. Per ogni passaggio, prepara suggerimenti progressivi (dal più generico al più specifico)
    45→
    46→Quando lo studente fa domande:
    47→- Rispondi sempre con domande che lo guidano a ragionare
    48→- Mai rivelare la risposta direttamente
    49→- Usa esempi simili per chiarire concetti
    50→- Celebra i progressi e incoraggia
    51→
    52→Rispondi SEMPRE in italiano.`;
    53→
    54→// Convert SavedHomework to Homework type
    55→function toHomework(saved: SavedHomework): Homework {
    56→  return {
    57→    id: saved.id,
    58→    title: saved.title,
    59→    subject: saved.subject,
    60→    problemType: saved.problemType,
    61→    photoUrl: saved.photoUrl,
    62→    steps: saved.steps,
    63→    createdAt: saved.createdAt,
    64→    completedAt: saved.completedAt,
    65→  };
    66→}
    67→
    68→export function HomeworkHelpView() {
    69→  const [currentHomework, setCurrentHomework] = useState<Homework | null>(null);
    70→  const [showHistory, setShowHistory] = useState(false);
    71→  const [maieuticChat, setMaieuticChat] = useState<MaieuticMessage[]>([]);
    72→  const [chatInput, setChatInput] = useState('');
    73→  const [isLoadingChat, setIsLoadingChat] = useState(false);
    74→
    75→  // Subject confirmation dialog state
    76→  const [showSubjectDialog, setShowSubjectDialog] = useState(false);
    77→  const [detectedSubject, setDetectedSubject] = useState<Subject>('mathematics');
    78→  const [pendingHomework, setPendingHomework] = useState<Homework | null>(null);
    79→  const [connectedMaestro, setConnectedMaestro] = useState<Maestro | null>(null);
    80→
    81→  const { setCurrentMaestro } = useVoiceSessionStore();
    82→
    83→  // Load homework sessions from database API
    84→  const {
    85→    sessions: homeworkHistory,
    86→    loading: historyLoading,
    87→    saveSession,
    88→    updateSession,
    89→    deleteSession,
    90→  } = useHomeworkSessions();
    91→
    92→  // Convert SavedHomework[] to Homework[] for display
    93→  const displayHistory = homeworkHistory.map(toHomework);
    94→
    95→  // Handle subject confirmation from dialog
    96→  const handleSubjectConfirm = useCallback(async (subject: Subject, maestro: Maestro | null) => {
    97→    if (!pendingHomework) return;
    98→
    99→    // Update homework with confirmed subject
   100→    const confirmedHomework: Homework = {
   101→      ...pendingHomework,
   102→      subject,
   103→    };
   104→
   105→    setCurrentHomework(confirmedHomework);
   106→
   107→    // Save to database API
   108→    await saveSession({
   109→      title: confirmedHomework.title,
   110→      subject: confirmedHomework.subject,
   111→      problemType: confirmedHomework.problemType,
   112→      photoUrl: confirmedHomework.photoUrl,
   113→      steps: confirmedHomework.steps,
   114→      completedAt: confirmedHomework.completedAt,
   115→    });
   116→
   117→    setShowSubjectDialog(false);
   118→    setPendingHomework(null);
   119→
   120→    // If a Maestro was selected, set them as the current Maestro
   121→    if (maestro) {
   122→      setConnectedMaestro(maestro);
   123→      setCurrentMaestro(maestro);
   124→    }
   125→  }, [pendingHomework, saveSession, setCurrentMaestro]);
   126→
   127→  // Analyze photo and create homework with maieutic approach
   128→  const handleSubmitPhoto = useCallback(async (photo: File): Promise<Homework> => {
   129→    // Convert to base64
   130→    const base64 = await fileToBase64(photo);
   131→
   132→    // Call vision API to analyze problem
   133→    const response = await fetch('/api/homework/analyze', {
   134→      method: 'POST',
   135→      headers: { 'Content-Type': 'application/json' },
   136→      body: JSON.stringify({
   137→        image: base64,
   138→        systemPrompt: MAIEUTIC_SYSTEM_PROMPT,
   139→      }),
   140→    });
   141→
   142→    if (!response.ok) {
   143→      // Fallback: create mock homework for demo
   144→      const mockHomework: Homework = {
   145→        id: crypto.randomUUID(),
   146→        title: 'Problema da analizzare',
   147→        subject: 'mathematics' as Subject,
   148→        problemType: 'Esercizio',
   149→        photoUrl: base64,
   150→        steps: [
   151→          {
   152→            id: '1',
   153→            description: 'Leggi attentamente il problema e identifica i dati',
   154→            hints: [
   155→              'Cosa ti viene chiesto di trovare?',
   156→              'Quali numeri o valori sono forniti?',
   157→              'Ci sono relazioni tra questi dati?',
   158→            ],
   159→            studentNotes: '',
   160→            completed: false,
   161→          },
   162→          {
   163→            id: '2',
   164→            description: 'Individua la formula o il metodo da applicare',
   165→            hints: [
   166→              'Che tipo di problema è?',
   167→              'Quali formule conosci per questo tipo di problema?',
   168→              'Come si collegano i dati alla formula?',
   169→            ],
   170→            studentNotes: '',
   171→            completed: false,
   172→          },
   173→          {
   174→            id: '3',
   175→            description: 'Applica il metodo passo dopo passo',
   176→            hints: [
   177→              'Qual è il primo calcolo da fare?',
   178→              'Stai usando le unità di misura corrette?',
   179→              'Il risultato intermedio ha senso?',
   180→            ],
   181→            studentNotes: '',
   182→            completed: false,
   183→          },
   184→          {
   185→            id: '4',
   186→            description: 'Verifica il risultato',
   187→            hints: [
   188→              'Il risultato risponde alla domanda?',
   189→              'Ha senso nel contesto del problema?',
   190→              'Hai incluso le unità di misura?',
   191→            ],
   192→            studentNotes: '',
   193→            completed: false,
   194→          },
   195→        ],
   196→        createdAt: new Date(),
   197→      };
   198→
   199→      // Show subject confirmation dialog
   200→      setPendingHomework(mockHomework);
   201→      setDetectedSubject(mockHomework.subject);
   202→      setShowSubjectDialog(true);
   203→      return mockHomework;
   204→    }
   205→
   206→    const data = await response.json();
   207→    const homework: Homework = {
   208→      id: crypto.randomUUID(),
   209→      title: data.title || 'Problema da risolvere',
   210→      subject: data.subject || 'mathematics',
   211→      problemType: data.problemType || 'Esercizio',
   212→      photoUrl: base64,
   213→      steps: data.steps || [],
   214→      createdAt: new Date(),
   215→    };
   216→
   217→    // Show subject confirmation dialog
   218→    setPendingHomework(homework);
   219→    setDetectedSubject(homework.subject);
   220→    setShowSubjectDialog(true);
   221→    return homework;
   222→  }, []);
   223→
   224→  // Complete a step
   225→  const handleCompleteStep = useCallback(async (stepId: string) => {
   226→    if (!currentHomework) return;
   227→
   228→    const updatedHomework: Homework = {
   229→      ...currentHomework,
   230→      steps: currentHomework.steps.map(step =>
   231→        step.id === stepId ? { ...step, completed: true } : step
   232→      ),
   233→    };
   234→
   235→    // Check if all steps completed
   236→    const allCompleted = updatedHomework.steps.every(s => s.completed);
   237→    if (allCompleted) {
   238→      updatedHomework.completedAt = new Date();
   239→    }
   240→
   241→    setCurrentHomework(updatedHomework);
   242→
   243→    // Update in database API
   244→    await updateSession({
   245→      id: updatedHomework.id,
   246→      title: updatedHomework.title,
   247→      subject: updatedHomework.subject,
   248→      problemType: updatedHomework.problemType,
   249→      photoUrl: updatedHomework.photoUrl,
   250→      steps: updatedHomework.steps,
   251→      createdAt: updatedHomework.createdAt,
   252→      completedAt: updatedHomework.completedAt,
   253→    });
   254→  }, [currentHomework, updateSession]);
   255→
   256→  // Ask maieutic question
   257→  const handleAskQuestion = useCallback((question: string) => {
   258→    setMaieuticChat(prev => [...prev, {
   259→      role: 'user',
   260→      content: question,
   261→      timestamp: new Date(),
   262→    }]);
   263→    setChatInput('');
   264→
   265→    // Trigger API call - deferred to avoid declaration order issue
   266→    setTimeout(() => sendMaieuticMessage(question), 0);
   267→    // eslint-disable-next-line react-hooks/exhaustive-deps -- sendMaieuticMessage defined after
   268→  }, []);
   269→
   270→  // Build system prompt for maieutic chat - use Maestro if connected
   271→  const getMaieuticSystemPrompt = useCallback(() => {
   272→    const basePrompt = connectedMaestro
   273→      ? `Sei ${connectedMaestro.name}, ${connectedMaestro.specialty}. ${connectedMaestro.teachingStyle}
   274→
   275→${MAIEUTIC_SYSTEM_PROMPT}`
   276→      : MAIEUTIC_SYSTEM_PROMPT;
   277→
   278→    // Add homework context to system prompt
   279→    if (currentHomework) {
   280→      return `${basePrompt}
   281→
   282→CONTESTO DEL PROBLEMA:
   283→- Titolo: ${currentHomework.title}
   284→- Tipo: ${currentHomework.problemType}
   285→- Passaggi: ${currentHomework.steps.map((s, i) => `${i + 1}. ${s.description} (${s.completed ? 'completato' : 'da fare'})`).join('\n')}
   286→
   287→Guida lo studente attraverso questi passaggi usando domande maieutiche. Non dare risposte dirette.`;
   288→    }
   289→
   290→    return basePrompt;
   291→  }, [connectedMaestro, currentHomework]);
   292→
   293→  // Send message to maieutic API
   294→  const sendMaieuticMessage = useCallback(async (message: string) => {
   295→    setIsLoadingChat(true);
   296→
   297→    try {
   298→      const response = await fetch('/api/chat', {
   299→        method: 'POST',
   300→        headers: { 'Content-Type': 'application/json' },
   301→        body: JSON.stringify({
   302→          messages: [
   303→            ...maieuticChat.map(m => ({ role: m.role, content: m.content })),
   304→            { role: 'user', content: message },
   305→          ],
   306→          systemPrompt: getMaieuticSystemPrompt(),
   307→          maestroId: connectedMaestro?.id || 'maieutic',
   308→          enableTools: false, // No tools for maieutic chat
   309→        }),
   310→      });
   311→
   312→      if (!response.ok) {
   313→        const errorData = await response.json().catch(() => ({}));
   314→        throw new Error(errorData.message || 'Failed to get response');
   315→      }
   316→
   317→      const data = await response.json();
   318→
   319→      setMaieuticChat(prev => [...prev, {
   320→        role: 'assistant',
   321→        content: data.content || 'Mi dispiace, non ho capito. Puoi riformulare la domanda?',
   322→        timestamp: new Date(),
   323→      }]);
   324→    } catch (err) {
   325→      logger.error('Maieutic chat error', { error: String(err) });
   326→      setMaieuticChat(prev => [...prev, {
   327→        role: 'assistant',
   328→        content: 'Scusa, c\'è stato un problema. Prova a riformulare la domanda.',
   329→        timestamp: new Date(),
   330→      }]);
   331→    } finally {
   332→      setIsLoadingChat(false);
   333→    }
   334→  }, [maieuticChat, getMaieuticSystemPrompt, connectedMaestro]);
   335→
   336→  // Handle chat submit
   337→  const handleChatSubmit = useCallback(() => {
   338→    if (!chatInput.trim() || isLoadingChat) return;
   339→
   340→    setMaieuticChat(prev => [...prev, {
   341→      role: 'user',
   342→      content: chatInput,
   343→      timestamp: new Date(),
   344→    }]);
   345→    sendMaieuticMessage(chatInput);
   346→    setChatInput('');
   347→  }, [chatInput, isLoadingChat, sendMaieuticMessage]);
   348→
   349→  // Load homework from history
   350→  const loadHomework = useCallback((homework: Homework) => {
   351→    setCurrentHomework(homework);
   352→    setMaieuticChat([]);
   353→    setShowHistory(false);
   354→  }, []);
   355→
   356→  // Delete homework from history
   357→  const deleteHomework = useCallback(async (id: string) => {
   358→    await deleteSession(id);
   359→    if (currentHomework?.id === id) {
   360→      setCurrentHomework(null);
   361→    }
   362→  }, [currentHomework, deleteSession]);
   363→
   364→  // Start new homework
   365→  const startNew = useCallback(() => {
   366→    setCurrentHomework(null);
   367→    setMaieuticChat([]);
   368→  }, []);
   369→
   370→  return (
   371→    <div className="space-y-6">
   372→      {/* Header */}
   373→      <div className="flex items-center justify-between">
   374→        <div>
   375→          <h1 className="text-3xl font-bold text-slate-900 dark:text-white">
   376→            Materiali di Studio
   377→          </h1>
   378→          <p className="text-slate-600 dark:text-slate-400 mt-1">
   379→            Metodo maieutico: ti guido a trovare la soluzione da solo
   380→          </p>
   381→          {/* Connected Maestro badge */}
   382→          {connectedMaestro && (
   383→            <div className="mt-2 inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800">
   384→              <div
   385→                className="w-6 h-6 rounded-full flex items-center justify-center text-white text-xs font-bold"
   386→                style={{ backgroundColor: connectedMaestro.color }}
   387→              >
   388→                {connectedMaestro.avatar}
   389→              </div>
   390→              <span className="text-sm font-medium text-blue-700 dark:text-blue-300">
   391→                Con {connectedMaestro.name}
   392→              </span>
   393→              <GraduationCap className="w-4 h-4 text-blue-500" />
   394→            </div>
   395→          )}
   396→        </div>
   397→        <div className="flex gap-2">
   398→          {currentHomework && (
   399→            <Button variant="outline" onClick={startNew}>
   400→              Nuovo problema
   401→            </Button>
   402→          )}
   403→          <Button
   404→            variant="outline"
   405→            onClick={() => setShowHistory(!showHistory)}
   406→            className={cn(showHistory && 'bg-slate-100 dark:bg-slate-800')}
   407→          >
   408→            <History className="w-4 h-4 mr-2" />
   409→            Cronologia ({displayHistory.length})
   410→          </Button>
   411→        </div>
   412→      </div>
   413→
   414→      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
   415→        {/* Main content */}
   416→        <div className={cn('lg:col-span-2', showHistory && 'lg:col-span-2')}>
   417→          {/* Subject Confirmation - shown inline after photo capture */}
   418→          {showSubjectDialog ? (
   419→            <SubjectConfirmationDialog
   420→              key={pendingHomework?.id || detectedSubject}
   421→              detectedSubject={detectedSubject}
   422→              isOpen={showSubjectDialog}
   423→              photoPreview={pendingHomework?.photoUrl}
   424→              onConfirm={handleSubjectConfirm}
   425→              onClose={() => {
   426→                setShowSubjectDialog(false);
   427→                setPendingHomework(null);
   428→              }}
   429→            />
   430→          ) : (
   431→            <HomeworkHelp
   432→              homework={currentHomework || undefined}
   433→              onSubmitPhoto={handleSubmitPhoto}
   434→              onCompleteStep={handleCompleteStep}
   435→              onAskQuestion={handleAskQuestion}
   436→            />
   437→          )}
   438→        </div>
   439→
   440→        {/* Sidebar: History or Chat */}
   441→        <div className="space-y-4">
   442→          {/* History panel */}
   443→          <AnimatePresence>
   444→            {showHistory && (
   445→              <motion.div
   446→                initial={{ opacity: 0, x: 20 }}
   447→                animate={{ opacity: 1, x: 0 }}
   448→                exit={{ opacity: 0, x: 20 }}
   449→              >
   450→                <Card>
   451→                  <CardHeader className="pb-3">
   452→                    <CardTitle className="text-lg flex items-center justify-between">
   453→                      <span>Cronologia</span>
   454→                      <Button
   455→                        variant="ghost"
   456→                        size="icon-sm"
   457→                        onClick={() => setShowHistory(false)}
   458→                        aria-label="Chiudi cronologia"
   459→                      >
   460→                        <X className="w-4 h-4" />
   461→                      </Button>
   462→                    </CardTitle>
   463→                  </CardHeader>
   464→                  <CardContent className="space-y-2 max-h-96 overflow-y-auto">
   465→                    {historyLoading ? (
   466→                      <div className="flex items-center justify-center py-8">
   467→                        <Loader2 className="w-6 h-6 animate-spin text-blue-500" />
   468→                      </div>
   469→                    ) : displayHistory.length === 0 ? (
   470→                      <p className="text-sm text-slate-500 text-center py-4">
   471→                        Nessun problema salvato
   472→                      </p>
   473→                    ) : (
   474→                      displayHistory.map(hw => (
   475→                        <div
   476→                          key={hw.id}
   477→                          className={cn(
   478→                            'p-3 rounded-lg border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800/50 cursor-pointer transition-colors group',
   479→                            currentHomework?.id === hw.id && 'ring-2 ring-blue-500 bg-blue-50 dark:bg-blue-900/20'
   480→                          )}
   481→                          onClick={() => loadHomework(hw)}
   482→                        >
   483→                          <div className="flex items-start justify-between">
   484→                            <div className="flex-1 min-w-0">
   485→                              <p className="font-medium text-sm truncate">
   486→                                {hw.title}
   487→                              </p>
   488→                              <p className="text-xs text-slate-500 mt-0.5">
   489→                                {hw.steps.filter(s => s.completed).length}/{hw.steps.length} passaggi
   490→                              </p>
   491→                              <p className="text-xs text-slate-400 mt-1">
   492→                                {new Date(hw.createdAt).toLocaleDateString('it-IT')}
   493→                              </p>
   494→                            </div>
   495→                            <div className="flex items-center gap-1">
   496→                              {hw.completedAt && (
   497→                                <CheckCircle className="w-4 h-4 text-green-500" />
   498→                              )}
   499→                              <Button
   500→                                variant="ghost"
   501→                                size="icon-sm"
   502→                                className="opacity-0 group-hover:opacity-100"
   503→                                onClick={(e) => {
   504→                                  e.stopPropagation();
   505→                                  deleteHomework(hw.id);
   506→                                }}
   507→                                aria-label="Elimina problema"
   508→                              >
   509→                                <Trash2 className="w-3 h-3 text-red-500" />
   510→                              </Button>
   511→                            </div>
   512→                          </div>
   513→                        </div>
   514→                      ))
   515→                    )}
   516→                  </CardContent>
   517→                </Card>
   518→              </motion.div>
   519→            )}
   520→          </AnimatePresence>
   521→
   522→          {/* Maieutic chat */}
   523→          {currentHomework && (
   524→            <Card>
   525→              <CardHeader className="pb-3">
   526→                <CardTitle className="text-lg flex items-center gap-2">
   527→                  <MessageCircle className="w-5 h-5 text-blue-500" />
   528→                  Dialogo Maieutico
   529→                </CardTitle>
   530→              </CardHeader>
   531→              <CardContent>
   532→                <div className="space-y-3 max-h-80 overflow-y-auto mb-4">
   533→                  {maieuticChat.length === 0 ? (
   534→                    <div className="text-center py-6">
   535→                      <p className="text-sm text-slate-500">
   536→                        Hai dubbi? Chiedimi aiuto!
   537→                      </p>
   538→                      <p className="text-xs text-slate-400 mt-1">
   539→                        Ti guiderò con domande
   540→                      </p>
   541→                    </div>
   542→                  ) : (
   543→                    maieuticChat.map((msg, i) => (
   544→                      <motion.div
   545→                        key={i}
   546→                        initial={{ opacity: 0, y: 10 }}
   547→                        animate={{ opacity: 1, y: 0 }}
   548→                        className={cn(
   549→                          'p-3 rounded-lg text-sm',
   550→                          msg.role === 'user'
   551→                            ? 'bg-accent-themed text-white ml-8'
   552→                            : 'bg-slate-100 dark:bg-slate-800 mr-8'
   553→                        )}
   554→                      >
   555→                        {msg.content}
   556→                      </motion.div>
   557→                    ))
   558→                  )}
   559→                  {isLoadingChat && (
   560→                    <div className="flex items-center gap-2 text-sm text-slate-500 p-3">
   561→                      <Loader2 className="w-4 h-4 animate-spin" />
   562→                      Sto pensando...
   563→                    </div>
   564→                  )}
   565→                </div>
   566→
   567→                {/* Chat input */}
   568→                <div className="flex gap-2">
   569→                  <input
   570→                    type="text"
   571→                    value={chatInput}
   572→                    onChange={(e) => setChatInput(e.target.value)}
   573→                    onKeyDown={(e) => e.key === 'Enter' && handleChatSubmit()}
   574→                    placeholder="Fai una domanda..."
