                    </p>
                  </div>
                  <ArrowRight className="h-5 w-5 text-slate-400" />
                </button>
              </div>

              <Button
                variant="outline"
                onClick={() => setShowMaestroSelection(false)}
                className="w-full"
              >
                <ArrowLeft className="mr-2 h-4 w-4" />
                Torna alla selezione materia
              </Button>
            </>
          )}
        </CardContent>
      </Card>
    </motion.div>
  );
}

