// To:
"subject": "mathematics|physics|chemistry|biology|history|geography|italian|english|art|music|civics|economics|computerScience|health|philosophy|other"
```

3. Add a subject normalization function (after line 25):

```typescript
// Map common AI responses to valid Subject values
const SUBJECT_MAP: Record<string, string> = {
  'math': 'mathematics',
  'maths': 'mathematics',
  'matematica': 'mathematics',
  'science': 'biology', // Default science to biology, or could use context
  'scienze': 'biology',
  'fisica': 'physics',
  'chimica': 'chemistry',
  'biologia': 'biology',
  'storia': 'history',
  'geografia': 'geography',
  'italiano': 'italian',
  'inglese': 'english',
  'arte': 'art',
  'musica': 'music',
  'informatica': 'computerScience',
  'filosofia': 'philosophy',
  'economia': 'economics',
  'educazione_civica': 'civics',
  'diritto': 'internationalLaw',
};

const VALID_SUBJECTS = [
  'mathematics', 'physics', 'chemistry', 'biology', 'history', 'geography',
  'italian', 'english', 'art', 'music', 'civics', 'economics',
  'computerScience', 'health', 'philosophy', 'internationalLaw'
];

function normalizeSubject(subject: string): string {
  const lower = subject.toLowerCase();
  if (VALID_SUBJECTS.includes(lower)) return lower;
  if (SUBJECT_MAP[lower]) return SUBJECT_MAP[lower];
  return 'other';
}
```

4. Apply normalization after parsing (around line 131):

