**Step 1: Create API endpoint**

**File**: `/src/app/api/materials/search/route.ts` (NEW FILE)

```typescript
import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { logger } from '@/lib/logger';

export async function POST(request: NextRequest) {
  try {
    const { query, toolType, subject, limit = 5 } = await request.json();

    // Build where clause
    const where: Record<string, unknown> = {
      status: 'active',
    };

    if (toolType) {
      where.toolType = toolType;
    }

    if (subject) {
      where.subject = subject;
    }

    // Search in title, topic, and content
    const materials = await prisma.material.findMany({
      where: {
        ...where,
        OR: query ? [
          { title: { contains: query } },
          { topic: { contains: query } },
        ] : undefined,
      },
      orderBy: { createdAt: 'desc' },
      take: limit,
      select: {
        id: true,
        toolId: true,
        toolType: true,
        title: true,
        subject: true,
        preview: true,
        createdAt: true,
        maestroId: true,
      },
    });

    return NextResponse.json({ materials });
  } catch (error) {
    logger.error('Material search failed', { error });
    return NextResponse.json({ error: 'Search failed' }, { status: 500 });
  }
}
```

**Step 2: Create tool handler**

**File**: `/src/lib/tools/handlers/archive-handler.ts` (NEW FILE)

```typescript
import { registerToolHandler } from '../tool-executor';
import { nanoid } from 'nanoid';
import { logger } from '@/lib/logger';
import type { ToolExecutionResult } from '@/types/tools';

interface ArchiveSearchResult {
  id: string;
  toolId: string;
  toolType: string;
  title: string;
  subject?: string;
  preview?: string;
  createdAt: string;
  maestroId?: string;
}

interface ArchiveSearchData {
  query: string;
  toolType?: string;
  subject?: string;
  results: ArchiveSearchResult[];
  totalFound: number;
}

registerToolHandler('search_archive', async (args): Promise<ToolExecutionResult> => {
  const { query, toolType, subject } = args as {
    query?: string;
    toolType?: string;
    subject?: string;
  };

  if (!query && !toolType && !subject) {
    return {
      success: false,
      toolId: nanoid(),
      toolType: 'search',
      error: 'Almeno uno tra query, toolType o subject è richiesto',
    };
  }

  try {
    const response = await fetch('/api/materials/search', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ query, toolType, subject }),
    });

    if (!response.ok) {
      throw new Error('Search API failed');
    }

    const { materials } = await response.json();

    const data: ArchiveSearchData = {
      query: query || '',
      toolType,
      subject,
      results: materials,
      totalFound: materials.length,
    };

    return {
      success: true,
      toolId: nanoid(),
      toolType: 'search',
      data,
    };
  } catch (error) {
    logger.error('Archive search failed', { error });
    return {
      success: false,
      toolId: nanoid(),
      toolType: 'search',
      error: 'Ricerca archivio fallita',
    };
  }
});
```

