  // English abbreviations
  'math': 'mathematics',
  'maths': 'mathematics',
  'science': 'biology',
  'cs': 'computerScience',
  'pe': 'health',
  'law': 'internationalLaw',
  // Italian names
  'matematica': 'mathematics',
