  1003→/**
  1004→ * Maps voice tool names to ToolType.
  1005→ */
  1006→export function getToolTypeFromName(name: string): ToolType | null {
  1007→  switch (name) {
  1008→    case 'create_mindmap':
  1009→      return 'mindmap';
  1010→    case 'create_quiz':
  1011→      return 'quiz';
  1012→    case 'create_flashcards':
  1013→      return 'flashcards';
  1014→    case 'create_summary':
  1015→    case 'open_student_summary': // #70 maieutic method
  1016→      return 'summary';
  1017→    case 'create_diagram':
  1018→      return 'diagram';
  1019→    case 'create_timeline':
  1020→      return 'timeline';
  1021→    case 'create_demo':
  1022→      return 'demo';
  1023→    default:
  1024→      return null;
  1025→  }
  1026→}
  1027→
  1028→/**
  1029→ * Check if a tool name is a tool creation command.
  1030→ */
  1031→export function isToolCreationCommand(name: string): boolean {
  1032→  return getToolTypeFromName(name) !== null;
  1033→}
