          type: 'string',
          description: 'Materia',
        },
      },
      required: ['title', 'type', 'topic'],
    },
  },
  {
    type: 'function',
    name: 'create_timeline',
    description:
      'Crea una linea del tempo per eventi storici o sequenze temporali.',
    parameters: {
      type: 'object',
      properties: {
        title: {
          type: 'string',
          description: 'Titolo della timeline',
