// Mindmap specific types
// ============================================================================

export interface MindmapNode {
  id: string;
  label: string;
  parentId?: string | null;
}

export interface MindmapData {
  topic: string;
  nodes: MindmapNode[];
  markdown?: string;
}

// ============================================================================
// Quiz specific types
// ============================================================================

export interface QuizQuestion {
  question: string;
  options: string[];
  correctIndex: number;
  explanation?: string;
}

export interface QuizData {
  topic: string;
  questions: QuizQuestion[];
}

// ============================================================================
// Demo specific types
// ============================================================================

export interface DemoData {
  title: string;
  description?: string;
  html: string;
  css?: string;
  js?: string;
}

// ============================================================================
// Search specific types
// ============================================================================

export interface SearchResult {
  type: 'web' | 'youtube';
  title: string;
  url: string;
  description?: string;
  thumbnail?: string;
  duration?: string; // YouTube only
}

export interface SearchData {
  query: string;
  searchType: 'web' | 'youtube' | 'all';
  results: SearchResult[];
}

// ============================================================================
// Flashcard specific types
// ============================================================================

export interface FlashcardItem {
  front: string;
  back: string;
}

export interface FlashcardData {
  topic: string;
  cards: FlashcardItem[];
}

// ============================================================================
// Summary specific types
// ============================================================================

export interface SummarySection {
  title: string;
  content: string;
  keyPoints?: string[];
}

export interface SummaryData {
  topic: string;
  sections: SummarySection[];
  length?: 'short' | 'medium' | 'long';
}

// ============================================================================
// Student Summary types (maieutic method - student writes, AI guides)
// Issue #70: Collaborative summary writing
// ============================================================================

/**
 * Inline comment from Maestro on student's text
 */
export interface InlineComment {
  id: string;
  startOffset: number;
  endOffset: number;
  text: string;
  maestroId: string;
  createdAt: Date;
  resolved?: boolean;
}

/**
 * A guided section in student's summary
 */
export interface StudentSummarySection {
  id: string;
  heading: string;
  guidingQuestion: string;
  content: string;
  comments: InlineComment[];
}

/**
 * Student-written summary
 */
export interface StudentSummaryData {
  id: string;
  title: string;
  topic: string;
  sections: StudentSummarySection[];
  wordCount: number;
  createdAt: Date;
  lastModifiedAt: Date;
  maestroId?: string;
  sessionId?: string;
}

/**
 * Default guided structure template
 */
export const SUMMARY_STRUCTURE_TEMPLATE: Omit<StudentSummarySection, 'comments'>[] = [
  {
    id: 'intro',
    heading: 'Introduzione',
    guidingQuestion: 'Di cosa parla questo argomento? Qual è il tema principale?',
    content: '',
  },
  {
    id: 'main',
    heading: 'Sviluppo',
    guidingQuestion: 'Quali sono i punti chiave? Cosa hai capito di importante?',
    content: '',
  },
  {
    id: 'conclusion',
    heading: 'Conclusione',
    guidingQuestion: 'Quali conclusioni puoi trarre? Cosa è importante ricordare?',
    content: '',
  },
];

/**
 * Creates a new empty student summary
 */
export function createEmptyStudentSummary(
  topic: string,
  maestroId?: string,
  sessionId?: string
): StudentSummaryData {
  const now = new Date();
  return {
    id: crypto.randomUUID(),
    title: topic,
    topic,
    sections: SUMMARY_STRUCTURE_TEMPLATE.map((section) => ({
      ...section,
      comments: [],
    })),
    wordCount: 0,
    createdAt: now,
    lastModifiedAt: now,
    maestroId,
    sessionId,
  };
}

// ============================================================================
// Diagram specific types
// ============================================================================

export interface DiagramData {
  topic: string;
  diagramType: 'flowchart' | 'sequence' | 'class' | 'er';
  mermaidCode: string;
}

// ============================================================================
// Timeline specific types
// ============================================================================

export interface TimelineEvent {
  date: string;
  title: string;
  description?: string;
}

export interface TimelineData {
  topic: string;
  period?: string;
  events: TimelineEvent[];
}

